root.sql:
SELECT '!text1_1!' as text1, '!text2_1!' as text2 , sc_kep_t_monthly_receive.receive_year , sc_kep_t_monthly_receive.receive_month , pka_com_function.fp_get_member_name( sc_lon_m_contract.membership_no ) as memname, sc_lon_m_contract.membership_no, sc_lon_m_rule.loan_type, sc_lon_m_rule.loan_type_description, sc_lon_m_contract.loan_contract_no, pka_com_function.fp_get_thaidate(sc_lon_m_contract.begining_of_contract, 'SD MONTH YYYY') as begining_of_contract, sc_lon_m_contract.loan_approve_amount, pka_com_function.fp_get_thaidate(sc_kep_t_monthly_receive.receipt_date, 'MONTH YYYY') as receipt_tdate, pka_com_function.fp_get_thaidate(sc_kep_t_monthly_receive.receipt_date, 'SD MONTH YYYY') as receipt_date, sc_kep_t_monthly_receive_det.unkeep_money_amount, sc_cnt_m_coop.coop_name, sc_cnt_m_coop.address, sc_cnt_m_coop.tumbol_name, pka_com_function.fp_get_district_name( sc_cnt_m_coop.province_code , sc_cnt_m_coop.district_code) as district_name, pka_com_function.fp_get_province_name( sc_cnt_m_coop.province_code ) as province_name, sc_cnt_m_coop.postcode, sc_cnt_m_coop.manager_name, sc_mem_m_ucf_member_group.member_group_no, sc_mem_m_ucf_member_group.member_group_name, sc_lon_m_contract_coll.ref_own_no, pka_com_function.fp_get_member_name( sc_lon_m_contract_coll.ref_own_no ) as memname_coll, pka_com_function.fp_get_member_address_letter( sc_lon_m_contract_coll.ref_own_no , '0' , 1 ) as address_line1, pka_com_function.fp_get_member_address_letter( sc_lon_m_contract_coll.ref_own_no , '0' , 2 ) as address_line2, pka_com_function.fp_get_member_address_letter( sc_lon_m_contract_coll.ref_own_no , '0' , 3 ) as address_line3, pka_com_function.fp_get_member_address_letter( sc_lon_m_contract_coll.ref_own_no , '0' , 4 ) as address_line4, pka_com_function.fp_get_member_address_letter( sc_lon_m_contract_coll.ref_own_no , '0' , 5 ) as address_line5, '!text1_1!' as text1, '!text2_1!' as text2 FROM sc_lon_m_contract, sc_lon_m_rule, sc_kep_t_monthly_receive_det, sc_kep_t_monthly_receive, sc_cnt_m_coop, sc_mem_m_ucf_member_group, sc_lon_m_contract_coll WHERE 1 = 1 and ( sc_lon_m_contract.loan_type = sc_lon_m_rule.loan_type ) and ( sc_lon_m_contract.loan_contract_no = sc_kep_t_monthly_receive_det.receive_description ) and ( sc_kep_t_monthly_receive.membership_no = sc_kep_t_monthly_receive_det.membership_no ) and ( sc_kep_t_monthly_receive.receive_year = sc_kep_t_monthly_receive_det.receive_year ) and ( sc_kep_t_monthly_receive.receive_month = sc_kep_t_monthly_receive_det.receive_month ) and ( sc_kep_t_monthly_receive.seq_no = sc_kep_t_monthly_receive_det.seq_no ) and ( sc_kep_t_monthly_receive.member_group_no = sc_mem_m_ucf_member_group.member_group_no ) and ( sc_lon_m_contract.loan_contract_no = sc_lon_m_contract_coll.loan_contract_no ) and ( sc_kep_t_monthly_receive_det.unkeep_money_amount > 0 ) and ( sc_lon_m_contract_coll.collateral_type_code = '01' ) and ( sc_lon_m_contract_coll.status = '0' ) and ( sc_kep_t_monthly_receive.ppm_status = '0' )
/*WHERE*/ --and sc_kep_t_monthly_receive.receive_year = 2022 --and sc_kep_t_monthly_receive.receive_month = 1 --and sc_mem_m_ucf_member_group.member_group_no = '080202' --and sc_lon_m_contract.membership_no = '000669'
ORDER BY sc_mem_m_ucf_member_group.member_group_no ASC, sc_lon_m_contract.membership_no ASC , sc_lon_m_contract_coll.ref_own_no ASC
